import{_ as n,C as i,o as a,c as d,j as e,a as r,b as l,w as o,E as D,a3 as B,a2 as u}from"./chunks/framework.DGp-bpT-.js";const A=JSON.parse('{"title":"Введение в SREBot — AI SRE-копилот для Kubernetes","description":"Документация SREBot: AI-бот для автоматического анализа первопричин инцидентов в Kubernetes. Интеграция с Telegram, Slack, Discord, Prometheus, Elasticsearch.","frontmatter":{"title":"Введение в SREBot — AI SRE-копилот для Kubernetes","description":"Документация SREBot: AI-бот для автоматического анализа первопричин инцидентов в Kubernetes. Интеграция с Telegram, Slack, Discord, Prometheus, Elasticsearch.","head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/guide/introduction.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/introduction.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/introduction.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/introduction.md"}]]},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1779961114000}'),g={name:"guide/introduction.md"};function h(c,t,m,p,E,b){const s=i("Mermaid");return a(),d("div",null,[t[1]||(t[1]=e("h1",{id:"введение-в-srebot",tabindex:"-1"},[r("Введение в SREBot "),e("a",{class:"header-anchor",href:"#введение-в-srebot","aria-label":'Permalink to "Введение в SREBot"'},"​")],-1)),t[2]||(t[2]=e("p",null,[e("strong",null,"SREBot"),r(" — это интеллектуальная платформа для observability и мониторинга, которая помогает быстро находить первопричины инцидентов (Root Cause Analysis).")],-1)),t[3]||(t[3]=e("p",null,[r("Она интегрируется напрямую с "),e("strong",null,"Telegram-чатом"),r(' вашей команды. Бот деплоится внутри вашей собственной Kubernetes-инфраструктуры, "слушает" сообщения Prometheus Alertmanager и автоматически проводит конфиденциальный анализ метрик (Prometheus) и логов (Elasticsearch).')],-1)),t[4]||(t[4]=e("h2",{id:"как-это-работает",tabindex:"-1"},[r("Как это работает? "),e("a",{class:"header-anchor",href:"#как-это-работает","aria-label":'Permalink to "Как это работает?"'},"​")],-1)),(a(),l(B,null,{default:o(()=>[D(s,{id:"mermaid-12",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Alertmanager%0A%20%20%20%20participant%20TelegramChat%20as%20%D0%A7%D0%B0%D1%82%20%D0%BA%D0%BE%D0%BC%D0%B0%D0%BD%D0%B4%D1%8B%20(Telegram)%0A%20%20%20%20participant%20SREBot%20as%20SREBot%20(%D0%B2%20%D0%B2%D0%B0%D1%88%D0%B5%D0%BC%20K8s)%0A%20%20%20%20participant%20Backend%20as%20AI%20Backend%0A%0A%20%20%20%20Alertmanager-%3E%3ETelegramChat%3A%20%D0%A1%D0%BE%D0%BE%D0%B1%D1%89%D0%B5%D0%BD%D0%B8%D0%B5%20%D1%81%20%D0%B3%D1%80%D1%83%D0%BF%D0%BF%D0%BE%D0%B9%20%D0%B0%D0%BB%D0%B5%D1%80%D1%82%D0%BE%D0%B2%0A%20%20%20%20SREBot-%3E%3ETelegramChat%3A%20%D0%90%D0%B2%D1%82%D0%BE%D1%80%D0%B8%D0%B7%D1%83%D0%B5%D1%82%D1%81%D1%8F%20%D0%B8%20%D1%87%D0%B8%D1%82%D0%B0%D0%B5%D1%82%20%D1%81%D0%BE%D0%BE%D0%B1%D1%89%D0%B5%D0%BD%D0%B8%D1%8F%0A%20%20%20%20SREBot-%3E%3EBackend%3A%20%D0%97%D0%B0%D0%BF%D1%80%D0%BE%D1%81%20%D0%BD%D0%B0%20%D0%B0%D0%BD%D0%B0%D0%BB%D0%B8%D0%B7%0A%20%20%20%20Backend--%3E%3ESREBot%3A%20%D0%94%D0%B5%D1%82%D0%B0%D0%BB%D1%8C%D0%BD%D1%8B%D0%B9%20RCA%20%D0%BE%D1%82%D1%87%D0%B5%D1%82%0A%20%20%20%20SREBot--%3E%3ETelegramChat%3A%20Reply%20%D0%BD%D0%B0%20%D0%BE%D1%80%D0%B8%D0%B3%D0%B8%D0%BD%D0%B0%D0%BB%D1%8C%D0%BD%D0%BE%D0%B5%20%D1%81%D0%BE%D0%BE%D0%B1%D1%89%D0%B5%D0%BD%D0%B8%D0%B5%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[r(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=u('<ol><li><strong>Развертывание (Helm):</strong> Бот SREBot устанавливается в ваш Kubernetes кластер и автоматически регистрируется в целевом Telegram-чате.</li><li><strong>Получение алерта:</strong> Alertmanager отправляет стандартное сообщение инцидента в общий чат.</li><li><strong>Дедупликация:</strong> Бот перехватывает сообщение. Если инцидент с подобным отпечатком (fingerprint) уже анализируется, бот игнорирует дубликаты.</li><li><strong>Анализ:</strong> AI-агент использует предоставленные доступы (Prometheus URL, Elasticsearch URL) из вашего приватного контура Kubernetes для безопасного поиска информации.</li><li><strong>Результат:</strong> Бот отправляет готовый RCA отчет ответом (reply) на сообщение Alertmanager.</li></ol><h2 id="ключевые-возможности" tabindex="-1">Ключевые возможности <a class="header-anchor" href="#ключевые-возможности" aria-label="Permalink to &quot;Ключевые возможности&quot;">​</a></h2><ul><li><strong>Автоматический RCA:</strong> Моментальный анализ инцидентов на основе метрик и логов.</li><li><strong>Интерактивные уточнения:</strong> Возможность задавать боту дополнительные вопросы прямо в чате (через Reply), чтобы углубиться в детали.</li><li><strong>Безопасный доступ:</strong> Бот читает данные только из вашего приватного контура.</li><li><strong>Мультиязычность:</strong> Бот может отвечать на русском или английском языках в зависимости от настроек.</li></ul><h2 id="преимущества" tabindex="-1">Преимущества <a class="header-anchor" href="#преимущества" aria-label="Permalink to &quot;Преимущества&quot;">​</a></h2><ul><li><strong>Безопасность данных:</strong> Бот работает прямо в вашей внутренней K8s сети, не требуя публичных выходов (Ingress) для баз данных. Расследование происходит без утечки архитектурных деталей.</li><li><strong>Снижение MTTD/MTTR:</strong> AI-агент автоматизирует рутинный этап траблшутинга.</li><li><strong>Интуитивный дашборд:</strong> Централизованный веб-портал позволяет аналитикам проверить всю историю логики AI-агента.</li></ul><h2 id="открытыи-исходныи-код" tabindex="-1">Открытый исходный код <a class="header-anchor" href="#открытыи-исходныи-код" aria-label="Permalink to &quot;Открытый исходный код&quot;">​</a></h2><p>Агент SREBot (компонент, который деплоится в вашу инфраструктуру) — <strong>полностью open-source</strong> и доступен на GitHub:</p><p>👉 <a href="https://github.com/shadrus/srebot" target="_blank" rel="noreferrer">github.com/shadrus/srebot</a></p><p>Вы можете самостоятельно изучить исходный код, убедиться в отсутствии нежелательных действий и при необходимости собрать собственный Docker-образ из исходников.</p><p>Перейдите к разделу <a href="/docs/guide/setup">Быстрый старт</a>, чтобы узнать, как задеплоить бота через Helm.</p><h2 id="содержание-документации" tabindex="-1">Содержание документации <a class="header-anchor" href="#содержание-документации" aria-label="Permalink to &quot;Содержание документации&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Раздел</th><th>Описание</th></tr></thead><tbody><tr><td><a href="/docs/guide/setup">Быстрый старт</a></td><td>Установка через Helm в Kubernetes</td></tr><tr><td><a href="/docs/guide/dashboard">Веб-дашборд</a></td><td>Управление ботами, инциденты, биллинг</td></tr><tr><td><a href="/docs/guide/organizations">Управление организациями</a></td><td>Multi-org, создание и переключение</td></tr><tr><td><a href="/docs/guide/team-management">Управление командой</a></td><td>Роли, приглашения, передача владения</td></tr><tr><td><a href="/docs/guide/interaction">Общение с ботом</a></td><td>Follow-up вопросы, mute/unmute</td></tr><tr><td><a href="/docs/guide/telegram-setup">Настройка Telegram</a></td><td>BotFather, Chat ID, группы</td></tr><tr><td><a href="/docs/guide/slack-setup">Настройка Slack</a></td><td>Socket Mode, токены, каналы</td></tr><tr><td><a href="/docs/guide/discord-setup">Настройка Discord</a></td><td>Bot Token, permissions, channels</td></tr><tr><td><a href="/docs/guide/alert-formatting">Форматирование алертов</a></td><td>Парсинг, regex, smart parsing</td></tr><tr><td><a href="/docs/guide/configuration">Конфигурация</a></td><td>Env vars, MCP-серверы, ignore rules</td></tr></tbody></table>',12))])}const R=n(g,[["render",h]]);export{A as __pageData,R as default};
